/******
 * =CQP_TOTAL_TTP_GWD / CQP_TOTAL_TTP_ANNUAL_USD
 * By Adriana Centellas
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}


return safeNumber((safeNumber(this.CQP_TOTAL_TTP_GWD) / safeNumber(this.CQP_TOTAL_TTP_ANNUAL_USD)) * 100);

