/*******
 * =CQP_TOTAL_IMPORTS_HISTORICAL + CQP_TOTAL_EXPORTS_HISTORICAL + CQP_TOTAL_DOMESTIC_HISTORICAL
 * By Adriana Centellas
 */

function safeNumber(v) {
