return safeNumber(this.CQP_TOTAL_IMPORTS_HISTORICAL) + safeNumber(this.CQP_TOTAL_EXPORTS_HISTORICAL) + safeNumber(this.CQP_TOTAL_DOMESTIC_HISTORICAL);

/*****
 * =((CQP_TOTAL_TTP_ANNUAL_USD/CQP_TOTAL_TTP_HISTORICAL)-1)*100
 * By Adriana Centellas
 */

// Convert any value to a safe number
function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let annualTTP = safeNumber(this.CQP_TOTAL_TTP_ANNUAL_USD);
let historicalTTP = safeNumber(this.CQP_TOTAL_TTP_HISTORICAL);

// Main calculation
var returnVar = (historicalTTP !== 0 && annualTTP !== 0)
  ? ((annualTTP / historicalTTP) - 1) * 100
  : 0;


// Remove classes first
setTimeout(function () {
  const inputSelector = $('[selector="CQP_TOTAL_TTP_VARIATION"] > div > input');
  inputSelector.removeClass('inputError inputOk');
}, 200);


// Only evaluate color if result is a valid number and not zero
if (!Number.isNaN(returnVar) && returnVar !== 0) {

  let valor = parseFloat(returnVar);

  setTimeout(function () {
    const inputSelector = $('[selector="CQP_TOTAL_TTP_VARIATION"] > div > input');
    inputSelector.removeClass('inputError inputOk');

    if (valor < 0) {
      inputSelector.addClass('inputError'); // red
    } else if (valor > 0) {
      inputSelector.addClass('inputOk'); // green
    }

  }, 500);
}

return returnVar;

/*******
 * Get percentage from CQP_COMMODITIES based on TOTAL_IMPORTS value
 *
 * It loops through all items in CQP_COMMODITIES and their LIMITS,
 * and returns the PERCENTAGE where:
 *   MIN <= CQP_TOTAL_IMPORTS_ANNUAL_USD <= MAX
 *
 * @param none
 * @return (Number|0) matching percentage or 0 if not found
 *
 * by Adriana Centellas
 *******/

// 1) Get filtered commodities array
var filtered = this._parent.CQP_COMMODITIES_FILTERED || [];

// 2) Get the total imports value (convert to Number safely)
var total = this.CQP_TOTAL_TTP_ANNUAL_USD;

total = Number(total);

if (isNaN(total)) {
  return 0;
}

// 3) Search for the matching range in all LIMITS
for (var i = 0; i < filtered.length; i++) {
  var item = filtered[i];
  if (item.TYPE === 'CARGO') {
    var limits = item && item.LIMITS ? item.LIMITS : [];

    for (var j = 0; j < limits.length; j++) {
      var band = limits[j];

      // Convert MIN and MAX to numbers (they come as strings)
      var min = Number(band.MIN);
      var max = Number(band.MAX);

      if (isNaN(min) || isNaN(max)) {
        continue; // skip invalid bands
      }

      // Check if total is within [MIN, MAX]
      if (total >= min && total <= max) {
        return band.PERCENTAGE; // found the matching percentage
      }
    }
  }
}

// 4) If no band matches, return null (or 0 if you prefer)
return 0;

/****
 * Validate GWP total at least reaches the premium minimum
 * By Adriana Centellas
 */

// Get filtered commodities array
var filtered = this._parent.CQP_COMMODITIES_FILTERED || [];

// Get the total GWP value
var total = parseFloat(this.CQP_TOTAL_TTP_GWD) || 0;

// Search for the matching premium minimum
var minPrem = 0;

for (var i = 0; i < filtered.length; i++) {
  var item = filtered[i];
  if (item.TYPE === 'CARGO') {
    minPrem = parseFloat(item.NWP_MIN_PREMIUM) || 0;
  }
}

// Format amount manually (PM safe)
function formatAmount(num) {
  num = parseFloat(num) || 0;
  return num
    .toFixed(2)
    .replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

var formattedMinPrem = formatAmount(minPrem);

// Compare values
if (this.CQP_CARGO_FORTE_NET_RATE == 0 && total < minPrem) {
  return {
    isValid: false,
    message: "The total amount is too low. The GWP total must be at least " + formattedMinPrem
  };
}

return {
  isValid: true,
  message: ""
};
